class Solution {
public:
    int shipWithinDays(vector<int>& weights, int days) {
        if (weights.empty()) return 0;

        int maxWeight = *max_element(weights.begin(), weights.end());
        long long totalWeight = accumulate(weights.begin(), weights.end(), 0LL);
        long long left = maxWeight, right = totalWeight;

        while (left < right) {
            long long mid = (left + right) / 2;
            int daysNeeded = 1, currWeight = 0;

            for (int w : weights) {
                if (currWeight + w > mid) {
                    daysNeeded++;
                    currWeight = 0;
                    if (daysNeeded > days) break;
                }
                currWeight += w;
            }

            if (daysNeeded > days) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return (int)left;
    }
};

