class Solution:
    def shipWithinDays(self, weights: List[int], days: int) -> int:
        if not weights:
            return 0

        maxWeight = max(weights)
        totalWeight = sum(weights)
        left, right = maxWeight, totalWeight

        while left < right:
            mid = (left + right) // 2
            daysNeeded, currWeight = 1, 0
            for weight in weights:
                if currWeight + weight > mid:
                    daysNeeded += 1
                    currWeight = 0
                    if daysNeeded > days:
                        break
                currWeight += weight

            if daysNeeded > days:
                left = mid + 1
            else:
                right = mid
        return left

