long long needed_days(int *weights, int n, long long cap) {
    long long cur = 0;
    long long days = 1; // start with day 1
    for (int i = 0; i < n; ++i) {
        if (cur + weights[i] <= cap) {
            cur += weights[i];
        } else {
            days++;
            cur = weights[i];
        }
    }
    return days;
}


int shipWithinDays(int *weights, int n, int days) {
    long long lo = 0, hi = 0;
    for (int i = 0; i < n; ++i) {
        if (weights[i] > lo) lo = weights[i]; // at least the heaviest package
        hi += weights[i];                     // at most sum of all packages
    }

    long long ans = hi;
    long long L = lo, R = hi;
    while (L <= R) {
        long long mid = L + (R - L) / 2;
        long long need = needed_days(weights, n, mid);
        if (need <= days) {
            ans = mid;
            R = mid - 1;
        } else {
            L = mid + 1;
        }
    }
    return (int)ans;
}

