class ShipCapacity {
    public int shipWithinDays(int[] weights, int days) {
        long lo = 0, hi = 0;
        for (int w : weights) {
            lo = Math.max(lo, w); // at least the heaviest package
            hi += w;              // at most sum of all weights
        }

        long ans = hi;
        long L = lo, R = hi;
        while (L <= R) {
            long mid = L + (R - L) / 2;
            if (neededDays(weights, mid) <= days) {
                ans = mid;
                R = mid - 1;
            } else {
                L = mid + 1;
            }
        }
        return (int) ans;
    }

    private int neededDays(int[] weights, long cap) {
        long cur = 0;
        int d = 1;
        for (int w : weights) {
            if (cur + w <= cap) {
                cur += w;
            } else {
                d++;
                cur = w;
            }
        }
        return d;
    }
}

